#include<bits/stdc++.h>
using namespace std;

const int INF = 0x3f3f3f3f;

void SOLVE()
{
    int maxx = INF;
    string s;
    cin >> s;
    vector<vector<int>> ans(s.size() + 6, vector<int>(s.size() + 6, INF));
    ans[0][s.size() + 1] = 0;
    ans[0][s.size()] = ans[1][s.size() + 1] = 1;


    for (int i = 0; i < s.size(); i++)//abbab
        for (int j = i+1; j <= s.size()-1; j++)
        {
            int l = i + 1, r = j + 1;//ans
            if (s[i] == s[j])
                ans[l][r] = min(ans[l][r], ans[l - 1][r + 1]);            
            if (j - i == 1)
            {
                ans[l][r] = min({ans[l][r], ans[l - 1][r], ans[l][r + 1]});
                continue;
            }
            ans[l][r] = min({ans[l][r], ans[l - 1][r] + 1, ans[l][r + 1] + 1});
        }
    for (int i = 1; i < s.size(); i++)
        maxx = min(maxx, ans[i][i + 1]);
    cout << maxx << '\n';
}

signed main()
{
    SOLVE();
    return 0;
}
